For per-ticker signals on rebalancing days:
  close = data.xs('Close', level=1, axis=1)
  lookback_returns = close.pct_change(lookback_days)
  # On rebalance days, rank and select top_n
  entries = pd.DataFrame(False, index=close.index, columns=close.columns)
  exits = pd.DataFrame(False, index=close.index, columns=close.columns)
  for i in range(lookback_days, len(close)):
    if i % rebalance_days == 0:
      day_rets = lookback_returns.iloc[i].dropna()
      day_rets = day_rets[day_rets > 0]  # absolute momentum filter
      if len(day_rets) > 0:
        selected = day_rets.nlargest(top_n).index.tolist()
        for col in close.columns:
          if col in selected:
            entries.iloc[i][col] = True
          else:
            exits.iloc[i][col] = True
  portfolio = vbt.Portfolio.from_signals(close, entries, exits, freq='D', init_cash=100_000, fees=0.001)
